@function_tool
def safe_execute(code: str) -> dict:
    allowed_deps = {'numpy', 'pandas', 'matplotlib'}

    # Parse imports and validate
    imports = extract_imports(code)
    invalid_deps = imports - allowed_deps

    if invalid_deps:
        return {"error": f"Blocked deps: {invalid_deps}"}

    # Execute in isolated sandbox
    result = docker_sandbox.run(code, timeout=30)
    return {
        'success': result.exit_code == 0,
        'output': result.stdout,
        'tests_passed': parse_test_results(result.stdout)
    }

